    // Original: new Complex(a/0, 0).asin() = new Complex(Infinity, 0).asin() = (PI/2, -Infinity)
    // Mutated:  new Complex(0, 0).asin() = (0, 0)
    expect(result.im).toBe(-Infinity);
  });
});
